input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    x = list(map(int, input().split()))
    s = []
    for _ in range(n):
        s.append(input().strip())

    # Group questions by profile
    from collections import defaultdict
    profile_questions = defaultdict(list)
    for j in range(m):
        mask = 0
        for i in range(n):
            if s[i][j] == '1':
                mask |= (1 << i)
        profile_questions[mask].append(j)

    r = [0] * n
    assignment = [0] * m  # p[j]

    # Process values from m down to 1
    profile_remaining = {mask: list(qs) for mask, qs in profile_questions.items()}

    for v in range(m, 0, -1):
        best_gain = -1
        best_mask = 0
        for mask, qs in profile_remaining.items():
            if not qs:
                continue
            gain = 0
            for i in range(n):
                delta = v if (mask >> i) & 1 else 0
                gain += abs(x[i] - r[i] - delta) - abs(x[i] - r[i])
            if gain > best_gain:
                best_gain = gain
                best_mask = mask
        j = profile_remaining[best_mask].pop()
        assignment[j] = v
        for i in range(n):
            if (best_mask >> i) & 1:
                r[i] += v

    print(*assignment)

